<?php use App\Helpers\Sanitizer; use App\Helpers\Url; $imagen=$pieza['imagen_grande'] ?: $pieza['thumbnail']; ?>
<main class="container"><a class="volver" href="<?= Sanitizer::html(Url::ruta('/inventario')) ?>">&larr; Volver al inventario</a><section class="detail-layout"><div class="detail-image"><?php if($imagen): ?><img src="<?= Sanitizer::html(Url::upload($imagen)) ?>" alt="<?= Sanitizer::html($pieza['nombre_parte']) ?>"><?php else: ?><div class="placeholder-xl"><?= Sanitizer::html(mb_substr($pieza['nombre_parte'],0,1)) ?></div><?php endif; ?></div><article class="card"><span class="eyebrow">Detalle de pieza</span><h1><?= Sanitizer::html($pieza['nombre_parte']) ?></h1><p class="muted"><?= Sanitizer::html($pieza['marca'].' '.$pieza['modelo'].' · '.$pieza['anio']) ?></p><p><?= Sanitizer::html($pieza['descripcion_corta']) ?></p><dl class="detail-list"><dt>Código</dt><dd><?= Sanitizer::html($pieza['codigo_inventario']) ?></dd><dt>Sección</dt><dd><?= Sanitizer::html($pieza['codigo_seccion'].' - '.$pieza['nombre_seccion']) ?></dd><dt>Condición</dt><dd><?= Sanitizer::html($pieza['condicion_pieza']) ?></dd><dt>Precio</dt><dd>$<?= Sanitizer::html(number_format((float)$pieza['precio'],2)) ?></dd><dt>Cantidad</dt><dd><?= (int)$pieza['cantidad'] ?></dd><dt>Estado</dt><dd><?= (int)$pieza['activo']===1?'Activo':'Inactivo' ?></dd></dl><?php if(!empty($pieza['observaciones'])): ?><h2>Observaciones</h2><p><?= Sanitizer::html($pieza['observaciones']) ?></p><?php endif; ?><div class="form-actions"><a class="btn" href="<?= Sanitizer::html(Url::ruta('/inventario/editar/'.$pieza['id_inventario'])) ?>">Editar</a><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/catalogo')) ?>">Ver catálogo público</a></div></article></section></main>
